1	package members
2	
3	import (
4		"strconv"
5		"time"
6	
7		"github.com/gin-gonic/gin"
8		"github.com/jackc/pgx/v5"
9		"github.com/jackc/pgx/v5/pgxpool"
10	
11		"fitcommerce/backend/internal/auth"
12		"fitcommerce/backend/internal/http/response"
13		"fitcommerce/backend/internal/middleware"
14	)
15	
16	type Handler struct {
17		db *pgxpool.Pool
18	}
19	
20	func NewHandler(db *pgxpool.Pool) *Handler {
21		return &Handler{db: db}
22	}
23	
24	func (h *Handler) RegisterRoutes(r gin.IRouter) {
25		g := r.Group("/members")
26		g.GET("", h.list)
27		g.POST("", middleware.RequireRoles(auth.RoleAdministrator, auth.RoleOperationsManager), h.create)
28		g.GET("/:id", h.get)
29		g.PATCH("/:id", middleware.RequireRoles(auth.RoleAdministrator, auth.RoleOperationsManager), h.update)
30		g.GET("/:id/orders", h.orders)
31		g.GET("/:id/group-buys", h.groupBuys)
32	}
33	
34	type memberResponse struct {
35		ID             string  `json:"id"`
36		UserID         string  `json:"user_id"`
37		LocationID     *string `json:"location_id"`
38		MembershipType string  `json:"membership_type"`
39		MembershipStart *string `json:"membership_start"`
40		MembershipEnd   *string `json:"membership_end"`
41		Status         string  `json:"status"`
42		CreatedAt      string  `json:"created_at"`
43	}
44	
45	func (h *Handler) list(c *gin.Context) {
46		page, _ := strconv.Atoi(c.DefaultQuery("page", "1"))
47		perPage, _ := strconv.Atoi(c.DefaultQuery("per_page", "25"))
48		if page < 1 { page = 1 }
49		if perPage < 1 || perPage > 100 { perPage = 25 }
50	
51		var total int
52		_ = h.db.QueryRow(c.Request.Context(), `SELECT COUNT(*) FROM members`).Scan(&total)
53	
54		rows, err := h.db.Query(c.Request.Context(), `
55			SELECT id, user_id, location_id, membership_type, membership_start::text, membership_end::text, status, created_at
56			FROM members ORDER BY created_at DESC LIMIT $1 OFFSET $2
57		`, perPage, (page-1)*perPage)
58		if err != nil { response.InternalError(c); return }
59		defer rows.Close()
60	
61		members := []memberResponse{}
62		for rows.Next() {
63			var m memberResponse
64			var createdAt time.Time
65			if rows.Scan(&m.ID, &m.UserID, &m.LocationID, &m.MembershipType, &m.MembershipStart, &m.MembershipEnd, &m.Status, &createdAt) == nil {
66				m.CreatedAt = createdAt.UTC().Format(time.RFC3339)
67				members = append(members, m)
68			}
69		}
70		response.OKPaginated(c, members, response.Meta{Page: page, PerPage: perPage, Total: total})
71	}
72	
73	func (h *Handler) create(c *gin.Context) {
74		response.NotImplemented(c)
75	}
76	
77	func (h *Handler) get(c *gin.Context) {
78		id := c.Param("id")
79		var m memberResponse
80		var createdAt time.Time
81		err := h.db.QueryRow(c.Request.Context(), `
82			SELECT id, user_id, location_id, membership_type, membership_start::text, membership_end::text, status, created_at
83			FROM members WHERE id = $1
84		`, id).Scan(&m.ID, &m.UserID, &m.LocationID, &m.MembershipType, &m.MembershipStart, &m.MembershipEnd, &m.Status, &createdAt)
85		if err == pgx.ErrNoRows { response.NotFound(c, "member"); return }
86		if err != nil { response.InternalError(c); return }
87		m.CreatedAt = createdAt.UTC().Format(time.RFC3339)
88		response.OK(c, m)
89	}
90	
91	func (h *Handler) update(c *gin.Context) {
92		response.NotImplemented(c)
93	}
94	
95	func (h *Handler) orders(c *gin.Context) {
96		memberID := c.Param("id")
97		rows, err := h.db.Query(c.Request.Context(), `
98			SELECT id, status, total_amount, created_at FROM orders WHERE member_id = $1 ORDER BY created_at DESC
99		`, memberID)
100		if err != nil { response.InternalError(c); return }
101		defer rows.Close()
102	
103		type orderSummary struct {
104			ID        string  `json:"id"`
105			Status    string  `json:"status"`
106			Total     float64 `json:"total_amount"`
107			CreatedAt string  `json:"created_at"`
108		}
109		results := []orderSummary{}
110		for rows.Next() {
111			var o orderSummary
112			var createdAt time.Time
113			if rows.Scan(&o.ID, &o.Status, &o.Total, &createdAt) == nil {
114				o.CreatedAt = createdAt.UTC().Format(time.RFC3339)
115				results = append(results, o)
116			}
117		}
118		response.OK(c, results)
119	}
120	
121	func (h *Handler) groupBuys(c *gin.Context) {
122		memberID := c.Param("id")
123		rows, err := h.db.Query(c.Request.Context(), `
124			SELECT g.id, g.title, g.status, p.quantity, p.joined_at
125			FROM group_buy_participants p
126			JOIN group_buys g ON g.id = p.group_buy_id
127			WHERE p.member_id = $1
128			ORDER BY p.joined_at DESC
129		`, memberID)
130		if err != nil { response.InternalError(c); return }
131		defer rows.Close()
132	
133		type gbSummary struct {
134			ID       string `json:"id"`
135			Title    string `json:"title"`
136			Status   string `json:"status"`
137			Quantity int    `json:"quantity"`
138			JoinedAt string `json:"joined_at"`
139		}
140		results := []gbSummary{}
141		for rows.Next() {
142			var g gbSummary
143			var joinedAt time.Time
144			if rows.Scan(&g.ID, &g.Title, &g.Status, &g.Quantity, &joinedAt) == nil {
145				g.JoinedAt = joinedAt.UTC().Format(time.RFC3339)
146				results = append(results, g)
147			}
148		}
149		response.OK(c, results)
150	}
