1	import { useEffect, useState } from 'react';
2	import {
3	  Alert, Box, Button, Card, CardContent, CircularProgress,
4	  MenuItem, Paper, TextField, ToggleButton, ToggleButtonGroup, Typography,
5	} from '@mui/material';
6	import TrendingUpIcon from '@mui/icons-material/TrendingUp';
7	import TrendingDownIcon from '@mui/icons-material/TrendingDown';
8	import PeopleIcon from '@mui/icons-material/People';
9	import FitnessCenterIcon from '@mui/icons-material/FitnessCenter';
10	import EventIcon from '@mui/icons-material/Event';
11	import BarChartIcon from '@mui/icons-material/BarChart';
12	import DownloadIcon from '@mui/icons-material/Download';
13	import { useAuthStore } from '../store/authStore';
14	import { hasPermission } from '../types/auth';
15	import type { DashboardKPI } from '../api/reports';
16	import { getDashboard, createExport } from '../api/reports';
17	
18	export function DashboardPage() {
19	  const { user } = useAuthStore();
20	  const canExport = hasPermission(user?.role, 'export:generate');
21	
22	  const [kpi, setKpi] = useState<DashboardKPI | null>(null);
23	  const [loading, setLoading] = useState(true);
24	  const [error, setError] = useState('');
25	  const [granularity, setGranularity] = useState<string>('monthly');
26	  const [locationId, setLocationId] = useState('');
27	  const [exporting, setExporting] = useState(false);
28	
29	  const fetchKPI = async () => {
30	    setLoading(true);
31	    setError('');
32	    try {
33	      const params: Record<string, string> = { granularity };
34	      if (locationId) params.location_id = locationId;
35	      setKpi(await getDashboard(params));
36	    } catch {
37	      setError('Failed to load dashboard data');
38	    } finally {
39	      setLoading(false);
40	    }
41	  };
42	
43	  useEffect(() => { fetchKPI(); }, [granularity, locationId]);
44	
45	  const handleExport = async (format: 'csv' | 'pdf') => {
46	    setExporting(true);
47	    try {
48	      await createExport('dashboard', format);
49	      alert(`${format.toUpperCase()} export queued. Check exports page.`);
50	    } catch {
51	      alert('Export failed');
52	    } finally {
53	      setExporting(false);
54	    }
55	  };
56	
57	  if (loading) {
58	    return (
59	      <Box display="flex" justifyContent="center" alignItems="center" minHeight={300}>
60	        <CircularProgress />
61	      </Box>
62	    );
63	  }
64	
65	  if (error) {
66	    return <Alert severity="error">{error}</Alert>;
67	  }
68	
69	  if (!kpi) {
70	    return <Typography color="text.secondary">No data available</Typography>;
71	  }
72	
73	  const kpiCards = [
74	    { label: 'Member Growth', value: kpi.member_growth, icon: <TrendingUpIcon />, color: '#4caf50' },
75	    { label: 'Member Churn', value: kpi.member_churn, icon: <TrendingDownIcon />, color: '#f44336' },
76	    { label: 'Renewal Rate', value: `${kpi.renewal_rate.toFixed(1)}%`, icon: <PeopleIcon />, color: '#2196f3' },
77	    { label: 'Engagement Events', value: kpi.engagement, icon: <EventIcon />, color: '#ff9800' },
78	    { label: 'Class Fill Rate', value: `${kpi.class_fill_rate.toFixed(1)}%`, icon: <FitnessCenterIcon />, color: '#9c27b0' },
79	    { label: 'Coach Productivity', value: kpi.coach_productivity, icon: <BarChartIcon />, color: '#00bcd4' },
80	  ];
81	
82	  return (
83	    <Box>
84	      <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, mb: 3, flexWrap: 'wrap' }}>
85	        <Typography variant="h5" sx={{ flexGrow: 1 }}>Dashboard</Typography>
86	        <ToggleButtonGroup value={granularity} exclusive
87	          onChange={(_, v) => { if (v) setGranularity(v); }} size="small">
88	          <ToggleButton value="daily">Daily</ToggleButton>
89	          <ToggleButton value="weekly">Weekly</ToggleButton>
90	          <ToggleButton value="monthly">Monthly</ToggleButton>
91	        </ToggleButtonGroup>
92	        <TextField size="small" label="Location ID" value={locationId}
93	          onChange={(e) => setLocationId(e.target.value)} sx={{ width: 200 }} />
94	        {canExport && (
95	          <>
96	            <Button size="small" variant="outlined" startIcon={<DownloadIcon />}
97	              onClick={() => handleExport('csv')} disabled={exporting}>CSV</Button>
98	            <Button size="small" variant="outlined" startIcon={<DownloadIcon />}
99	              onClick={() => handleExport('pdf')} disabled={exporting}>PDF</Button>
100	          </>
101	        )}
102	      </Box>
103	
104	      <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
105	        Period: {kpi.start_date} to {kpi.end_date}
106	      </Typography>
107	
108	      <Box sx={{ display: 'grid', gridTemplateColumns: { xs: '1fr', sm: '1fr 1fr', md: '1fr 1fr 1fr' }, gap: 2, mb: 3 }}>
109	        {kpiCards.map((card) => (
110	          <Card key={card.label}>
111	            <CardContent sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
112	              <Box sx={{ color: card.color, fontSize: 40 }}>{card.icon}</Box>
113	              <Box>
114	                <Typography variant="h4" fontWeight={700}>{card.value}</Typography>
115	                <Typography variant="body2" color="text.secondary">{card.label}</Typography>
116	              </Box>
117	            </CardContent>
118	          </Card>
119	        ))}
120	      </Box>
121	
122	      <Paper sx={{ p: 3 }}>
123	        <Typography variant="h6" gutterBottom>KPI Definitions</Typography>
124	        <Typography variant="body2"><strong>Member Growth:</strong> Count of new members created in the period.</Typography>
125	        <Typography variant="body2"><strong>Member Churn:</strong> Count of members who became inactive/cancelled/expired in the period.</Typography>
126	        <Typography variant="body2"><strong>Renewal Rate:</strong> Percentage of active members whose membership extends past the period end.</Typography>
127	        <Typography variant="body2"><strong>Engagement:</strong> Total engagement events (attendance, orders, bookings, group-buy joins) in the period.</Typography>
128	        <Typography variant="body2"><strong>Class Fill Rate:</strong> Average (booked_seats / capacity * 100) across classes in the period.</Typography>
129	        <Typography variant="body2"><strong>Coach Productivity:</strong> Count of completed classes in the period.</Typography>
130	      </Paper>
131	    </Box>
132	  );
133	}
