1	const BASE_URL = import.meta.env.VITE_API_URL ?? 'http://localhost:8080';
2	
3	const TOKEN_KEY = 'fc_access_token';
4	const REFRESH_KEY = 'fc_refresh_token';
5	
6	export function getAccessToken(): string | null {
7	  return localStorage.getItem(TOKEN_KEY);
8	}
9	export function getRefreshToken(): string | null {
10	  return localStorage.getItem(REFRESH_KEY);
11	}
12	export function setTokens(access: string, refresh: string): void {
13	  localStorage.setItem(TOKEN_KEY, access);
14	  localStorage.setItem(REFRESH_KEY, refresh);
15	}
16	export function clearTokens(): void {
17	  localStorage.removeItem(TOKEN_KEY);
18	  localStorage.removeItem(REFRESH_KEY);
19	}
20	
21	let isRefreshing = false;
22	let refreshSubscribers: Array<(token: string) => void> = [];
23	
24	function onRefreshed(token: string) {
25	  refreshSubscribers.forEach(cb => cb(token));
26	  refreshSubscribers = [];
27	}
28	
29	async function tryRefresh(): Promise<string | null> {
30	  const refreshToken = getRefreshToken();
31	  if (!refreshToken) return null;
32	
33	  const res = await fetch(`${BASE_URL}/api/v1/auth/refresh`, {
34	    method: 'POST',
35	    headers: { 'Content-Type': 'application/json' },
36	    body: JSON.stringify({ refresh_token: refreshToken }),
37	  });
38	
39	  if (!res.ok) {
40	    clearTokens();
41	    return null;
42	  }
43	
44	  const data = await res.json();
45	  const newAccess: string = data.data.access_token;
46	  const newRefresh: string = data.data.refresh_token;
47	  setTokens(newAccess, newRefresh);
48	  return newAccess;
49	}
50	
51	type RequestOptions = RequestInit & { skipAuth?: boolean };
52	
53	export async function apiRequest<T = unknown>(
54	  path: string,
55	  options: RequestOptions = {},
56	): Promise<T> {
57	  const { skipAuth = false, ...fetchOptions } = options;
58	  const url = `${BASE_URL}${path}`;
59	
60	  const headers: Record<string, string> = {
61	    'Content-Type': 'application/json',
62	    ...(fetchOptions.headers as Record<string, string>),
63	  };
64	
65	  if (!skipAuth) {
66	    const token = getAccessToken();
67	    if (token) headers['Authorization'] = `Bearer ${token}`;
68	  }
69	
70	  let res = await fetch(url, { ...fetchOptions, headers });
71	
72	  // Auto-refresh on 401
73	  if (res.status === 401 && !skipAuth) {
74	    if (isRefreshing) {
75	      const newToken = await new Promise<string>(resolve => {
76	        refreshSubscribers.push(resolve);
77	      });
78	      headers['Authorization'] = `Bearer ${newToken}`;
79	      res = await fetch(url, { ...fetchOptions, headers });
80	    } else {
81	      isRefreshing = true;
82	      const newToken = await tryRefresh();
83	      isRefreshing = false;
84	      if (!newToken) {
85	        // Refresh failed — dispatch logout event
86	        window.dispatchEvent(new CustomEvent('auth:logout'));
87	        throw new ApiError(401, 'Session expired');
88	      }
89	      onRefreshed(newToken);
90	      headers['Authorization'] = `Bearer ${newToken}`;
91	      res = await fetch(url, { ...fetchOptions, headers });
92	    }
93	  }
94	
95	  if (!res.ok) {
96	    let errorBody: unknown;
97	    try { errorBody = await res.json(); } catch { errorBody = null; }
98	    throw new ApiError(res.status, res.statusText, errorBody);
99	  }
100	
101	  // 204 No Content
102	  if (res.status === 204) return undefined as T;
103	
104	  const json = await res.json();
105	  return (json.data ?? json) as T;
106	}
107	
108	export class ApiError extends Error {
109	  constructor(
110	    public status: number,
111	    message: string,
112	    public body?: unknown,
113	  ) {
114	    super(message);
115	    this.name = 'ApiError';
116	  }
117	}
