export interface ClassItem {
  id: string;
  coach_id: string;
  location_id: string;
  name: string;
  description: string | null;
  scheduled_at: string;
  duration_minutes: number;
  capacity: number;
  booked_seats: number;
  status: string;
  created_at: string;
}

export interface ClassListResponse {
  data: ClassItem[];
  meta: { page: number; per_page: number; total: number };
}

export interface CreateClassPayload {
  coach_id: string;
  location_id: string;
  name: string;
  description?: string;
  scheduled_at: string;
  duration_minutes: number;
  capacity: number;
}

export interface UpdateClassPayload {
  name?: string;
  description?: string;
  scheduled_at?: string;
  duration_minutes?: number;
  capacity?: number;
}

